query:
{
  iamRoles(
    where: {
      OR: [
        {
          vms_SOME: {
            NOT: { publicIpAddress: { eq: null } }
            networkInterfaces_SOME: {
              securityGroups_SOME: {
                rules_SOME: {
                  direction: { eq: "Inbound" }
                  action: { eq: "Allow" }
                  OR: [
                    { sources_INCLUDES: "cidr:0.0.0.0/0" }
                    { sources_INCLUDES: "cidr:::/0" }
                  ]
                }
              }
            }
          }
        }
        {
          functions_SOME: {
            AND: [{ NOT: { functionURL: { eq: "" } } }, { authType: { eq: "NONE" } }]
          }
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
